// nullTerminatedString converts a byte slice to a Go string, stopping at the
// first NUL byte. Used to convert fixed-size C string arrays.
func nullTerminatedString(b []byte) string {
	for i, c := range b {
		if c == 0 {
			return string(b[:i])
		}
	}
	return string(b)
}

